int ai_multiplayer_awareness(object *objp, int awareness_level)
{
	int	rval=1;

#ifdef NETWORK
	if (Game_mode & GM_MULTI) 
	{
		if (awareness_level == 0)
			return 0;
		rval = multi_can_move_robot(objp-Objects, awareness_level);
	}
#endif

	return rval;

}

#ifndef NDEBUG
fix	Prev_boss_shields = -1;
#endif

