1924→//	Robots will become aware of the player based on something that occurred.
1925→//	The object (probably player or weapon) which created the awareness is objp.
1926→void create_awareness_event(object* objp, int type)
1927→{
1928→	//	If not in multiplayer, or in multiplayer with robots, do this, else unnecessary!
1929→	if (!(Game_mode & GM_MULTI) || (Game_mode & GM_MULTI_ROBOTS)) {
1930→		if (add_awareness_event(objp, type)) {
1931→			if (((P_Rand() * (type + 4)) >> 15) > 4)
1932→				Overall_agitation++;
