1939→// ----------------------------------------------------------------------------------
1940→void pae_aux(int segnum, int type, int level)
1941→{
1942→	int	j;
1943→
1944→	if (New_awareness[segnum] < type)
1945→		New_awareness[segnum] = type;
1946→
1947→	// Process children.
1948→	for (j = 0; j < MAX_SIDES_PER_SEGMENT; j++)
1949→		if (IS_CHILD(Segments[segnum].children[j]))
1950→			if (level <= 3)
1951→				if (type == 4)
1952→					pae_aux(Segments[segnum].children[j], type - 1, level + 1);
1953→				else
1954→					pae_aux(Segments[segnum].children[j], type, level + 1);
1955→}
1956→
1957→
1958→// ----------------------------------------------------------------------------------
1959→void process_awareness_events(void)
1960→{
1961→	int	i;
1962→
1963→	if (!(Game_mode & GM_MULTI) || (Game_mode & GM_MULTI_ROBOTS)) {
1964→		memset(New_awareness, 0, sizeof(New_awareness[0]) * (Highest_segment_index + 1));
1965→
1966→		for (i = 0; i < Num_awareness_events; i++)
1967→			pae_aux(Awareness_events[i].segnum, Awareness_events[i].type, 1);
1968→
1969→	}
1970→
1971→	Num_awareness_events = 0;
1972→}
